import{t as e}from"./supabase-QT4RuUVr.js";/* empty css              */document.getElementById(`loginForm`).addEventListener(`submit`,async t=>{t.preventDefault();let n=document.getElementById(`email`).value,r=document.getElementById(`password`).value,{error:i}=await e.auth.signInWithPassword({email:n,password:r});if(i){document.getElementById(`errorMessage`).textContent=i.message;return}window.location.href=`index.html`});